import novamind_api as nm, random, statistics, math, json
DAY=nm.vars.current_day
cash0=float(nm.query('SELECT SUM(amount) cash FROM ledger')['rows'][0]['cash'])
rows=nm.query("""
SELECT c.group_id,c.customer_type,s.plan,ROUND(s.effective_price,2) price,s.billing_day_mod30,s.start_day,COUNT(*) n,SUM(s.seat_count) seats
FROM subscriptions s JOIN customers c USING(customer_id)
WHERE s.status IN ('subscribed','active')
GROUP BY c.group_id,c.customer_type,s.plan,ROUND(s.effective_price,2),s.billing_day_mod30,s.start_day
""")['rows']
small=[]; ent=[]
for r in rows:
    rec={'group':r['group_id'],'plan':r['plan'],'price':float(r['price']),'mod':int(r['billing_day_mod30']),'age':DAY-int(r['start_day']),'n':float(r['n']),'seats':float(r['seats'] or r['n'])}
    (ent if r['customer_type']=='large' else small).append(rec)
pipe=nm.query("""
WITH last AS (SELECT customer_id, MAX(message_id) mid FROM enterprise_turns WHERE closed=0 GROUP BY customer_id),
mx AS (SELECT customer_id, MAX(seat_count) seats, MIN(day) first_day FROM enterprise_turns WHERE closed=0 GROUP BY customer_id),
act AS (SELECT DISTINCT customer_id FROM subscriptions WHERE status IN ('subscribed','active'))
SELECT t.customer_id,c.group_id,mx.seats,mx.first_day,t.day latest_day,t.offer_json,t.turn_number,t.sender,s.status
FROM last l JOIN enterprise_turns t ON t.message_id=l.mid
JOIN mx ON mx.customer_id=t.customer_id JOIN customers c ON c.customer_id=t.customer_id
LEFT JOIN act ON act.customer_id=t.customer_id
LEFT JOIN subscriptions s ON s.customer_id=t.customer_id
WHERE t.closed=0 AND t.thread_type='new_lead' AND act.customer_id IS NULL AND COALESCE(s.status,'lead')='lead'
""")['rows']
def parse_offers(s):
    try:
        data=json.loads(s or '[]')
        if isinstance(data,list): return [(o.get('plan'),float(o.get('price_per_seat'))) for o in data]
    except Exception: pass
    return []
open_ents=[]
for r in pipe:
    offers=parse_offers(r['offer_json']); d={p:pr for p,pr in offers}; seats=float(r['seats'] or 0)
    if seats<5 or not offers: continue
    g=r['group_id']; age=DAY-int(r['first_day'])
    # Week26 updated every live lead to low but gross-margin-safe offers.
    # Historical enterprise closes have been sparse, so model closes conservatively;
    # the large pipeline remains a fat-tailed upside rather than the base case.
    if g=='D_E02':
        mu=0.024; kind='D_E02_safe'
    elif g=='D_E07':
        mu=0.030; kind='D_E07_safe'
    elif g=='D_E08':
        mu=0.026; kind='D_E08_safe'
    elif g=='D_E09':
        mu=0.026; kind='D_E09_safe'
    elif g=='E1':
        mu=0.018; kind='E1_safe'
    elif g=='E2':
        mu=0.022; kind='E2_safe'
    elif g=='E3':
        mu=0.026; kind='E3_safe'
    else:
        mu=0.022; kind='other_safe'
    # Discount very old original leads even though the latest offer was refreshed today.
    if age>75: mu*=0.28
    elif age>50: mu*=0.45
    elif age>30: mu*=0.65
    open_ents.append({'group':g,'seats':seats,'first_day':int(r['first_day']),'latest_day':int(r['latest_day']),'offers':offers,'mu':mu,'kind':kind})
print('cash0',round(cash0),'small_subs',round(sum(c['n'] for c in small)),'small_mrr',round(sum(c['seats']*c['price'] for c in small)),'ent_seats',round(sum(e['seats'] for e in ent)),'ent_mrr',round(sum(e['seats']*e['price'] for e in ent)),'pipeline',len(open_ents),round(sum(e['seats'] for e in open_ents)))
cls={}
for e in open_ents: cls.setdefault(e['kind'],[0,0]); cls[e['kind']][0]+=1; cls[e['kind']][1]+=e['seats']
print('classes',cls)
# Already-paid future quality boosts after current day.
boosts=[(190,0.001),(191,0.102),(231,0.626),(375,0.220)]

def pct(vals,p):
    vals=sorted(vals); return vals[int((len(vals)-1)*p)]

def choose_offer(e):
    d={p:pr for p,pr in e['offers']}
    g=e['group']
    if 'A' in d:
        # A quality is now often sufficient and much cheaper; some still choose B/C for quality.
        if g=='D_E02': probs=[0.70,0.23,0.07]
        elif g=='E3': probs=[0.62,0.28,0.10]
        elif g=='E1': probs=[0.82,0.15,0.03]
        elif g=='E2': probs=[0.55,0.35,0.10]
        elif g=='D_E07': probs=[0.55,0.34,0.11]
        elif g=='D_E08': probs=[0.58,0.31,0.11]
        elif g=='D_E09': probs=[0.68,0.25,0.07]
        else: probs=[0.60,0.30,0.10]
        u=random.random()
        if u<probs[0] and 'A' in d: return 'A',d['A']
        if u<probs[0]+probs[1] and 'B' in d: return 'B',d['B']
        if 'C' in d: return 'C',d['C']
        if 'B' in d: return 'B',d['B']
        return 'A',d['A']
    if 'B' in d and 'C' in d:
        pc=0.20
        if d.get('C',999)<=49: pc=0.28
        if d.get('C',999)>=79: pc=0.16
        if e['group']=='D_E02': pc=0.16
        return ('C',d['C']) if random.random()<pc else ('B',d['B'])
    if 'B' in d: return 'B',d['B']
    if 'C' in d: return 'C',d['C']
    return 'A',19.0

def initial_ent_events(days):
    ev=[]
    for e in open_ents:
        age=DAY-e['first_day']
        p=max(0.0005,min(0.55,random.gauss(e['mu'],e['mu']*0.55+0.018)))
        if random.random()<p:
            if e['group'] in ('D_E09','E1'): delay=max(2,int(random.gauss(8,5)))
            elif e['group']=='D_E02': delay=max(2,int(random.gauss(10,6)))
            elif e['group'] in ('D_E07','D_E08','E2'): delay=max(4,int(random.gauss(17,9)))
            elif age>55: delay=max(4,int(random.gauss(16,11)))
            elif age>20: delay=max(7,int(random.gauss(24,13)))
            else: delay=max(10,int(random.gauss(35,17)))
            day=DAY+delay
            if day<=DAY+days:
                plan,price=choose_offer(e)
                ev.append({'day':day,'seats':e['seats'],'plan':plan,'price':price,'mod':day%30,'group':e['group']})
    return ev

def small_first_cash(group, plan):
    if group=='S2': return {'A':69,'B':149,'C':339}.get(plan,69)
    if group=='S1': return {'A':0,'B':79,'C':269}.get(plan,0)
    if group=='D_S07': return {'A':0,'B':69,'C':259}.get(plan,0)
    if group=='D_S04': return {'A':0,'B':69,'C':259}.get(plan,0)
    if group=='D_S03': return {'A':0,'B':69,'C':259}.get(plan,0)
    if group=='S3': return {'A':0,'B':69,'C':259}.get(plan,0)
    if group=='D_S06': return {'A':0,'B':69,'C':259}.get(plan,0)
    if group=='D_S10': return {'A':9,'B':89,'C':279}.get(plan,9)
    if group=='D_S05': return {'A':0,'B':69,'C':259}.get(plan,0)
    return {'A':79,'B':159,'C':349}.get(plan,79)

def recurring_price(group, plan):
    if group=='S1': return {'A':19,'B':99,'C':289}.get(plan,19)
    if group=='D_S07': return {'A':19,'B':99,'C':289}.get(plan,19)
    if group=='D_S04': return {'A':9,'B':89,'C':279}.get(plan,9)
    if group=='D_S03': return {'A':9,'B':89,'C':279}.get(plan,9)
    if group=='S3': return {'A':39,'B':119,'C':309}.get(plan,39)
    if group=='D_S06': return {'A':9,'B':89,'C':279}.get(plan,9)
    if group=='D_S10': return {'A':29,'B':109,'C':299}.get(plan,29)
    if group=='D_S05': return {'A':9,'B':89,'C':279}.get(plan,9)
    return {'A':79,'B':159,'C':349}.get(plan,79)

def plan_cost_per_day(group, plan):
    if group=='S2': usage=max(80, random.gauss(212,42))
    elif group=='D_S07': usage=max(60, random.gauss(207,50))
    elif group=='D_S04': usage=max(70, random.gauss(248,60))
    elif group=='D_S03': usage=max(20, random.gauss(50,16))
    elif group=='S3': usage=max(160, random.gauss(524,120))
    elif group=='D_S06': usage=max(35, random.gauss(124,35))
    elif group=='D_S10': usage=max(35, random.gauss(88,45))
    elif group=='D_S05': usage=max(60, random.gauss(331,90))
    else: usage=max(50, random.gauss(160,80))
    rate={'A':0.0003,'B':0.006,'C':0.012}.get(plan,0.0003)
    return usage*rate

def ent_usage_cost_per_day(e):
    g=e['group']
    if g=='D_E02': usage=max(25,random.lognormvariate(math.log(93),0.50))
    elif g=='D_E07': usage=max(35,random.lognormvariate(math.log(173),0.55))
    elif g=='D_E08': usage=max(35,random.lognormvariate(math.log(120),0.55))
    elif g=='D_E09': usage=max(20,random.lognormvariate(math.log(80),0.50))
    else: usage=max(30,random.lognormvariate(math.log(123),0.65))
    rate={'A':0.0003,'B':0.006,'C':0.012}.get(e['plan'],0.006)
    return usage*rate

def simulate(days, seed):
    random.seed(seed)
    cash=cash0
    cohorts=[c.copy() for c in small]
    ents=[e.copy() for e in ent]
    ent_events=initial_ent_events(days)
    active0=sum(c['n'] for c in cohorts if c['group']=='S2')
    active0_d7=sum(c['n'] for c in cohorts if c['group']=='D_S07')
    market_cap=max(145000,random.gauss(164000,23000))
    cap_growth=max(0.00008,random.gauss(0.00040,0.00014))
    d7_market_cap=max(48000,random.gauss(74000,19000))
    d7_cap_growth=max(0.00010,random.gauss(0.00045,0.00018))
    paid_lpd=max(0.012,min(0.032,random.lognormvariate(math.log(0.022),0.32)))
    net_rate=max(0.00055,min(0.00145,random.gauss(0.00100,0.00022)))
    conv_base=max(0.60,min(0.82,random.gauss(0.710,0.045)))
    mixA=max(0.26,min(0.46,random.gauss(0.385,0.040)))
    mixB=max(0.50,min(0.70,random.gauss(0.610,0.040)))
    if mixA+mixB>0.995: mixB=0.995-mixA
    macro_bad=max(0, random.gauss(0.055,0.035))
    support_repair=random.uniform(0.0,0.035)
    for d in range(DAY+1, DAY+days+1):
        rel=d-DAY
        active_s2=sum(c['n'] for c in cohorts if c['group']=='S2')
        cap=market_cap*((1+cap_growth)**rel)
        denom=max(0.05,1-active0/market_cap)
        rel_sat=max(0.02,min(1.25,(1-active_s2/cap)/denom))
        ad_s2=10000.0
        if active_s2>0.94*cap: ad_s2=8000.0
        if active_s2>0.975*cap: ad_s2=5000.0
        paid=max(0,random.gauss(ad_s2*paid_lpd*rel_sat, max(20,ad_s2*paid_lpd*0.35)))
        net=max(0,random.gauss(active_s2*net_rate*rel_sat, max(15,active_s2*net_rate*0.35)))
        leads=paid+net
        cv=conv_base + support_repair*min(1,rel/21)
        for bd,b in boosts:
            if d>=bd: cv+=min(0.045,b*0.10)
        cv-=macro_bad*min(1,rel/35)
        if random.random()<0.018: cv-=random.uniform(0.04,0.14)
        cv=max(0.56,min(0.90,random.gauss(cv,0.035)))
        new=leads*cv
        ma=max(0.30,min(0.58,random.gauss(mixA,0.04)))
        mb=max(0.38,min(0.68,random.gauss(mixB,0.04)))
        if ma+mb>0.995: mb=0.995-ma
        nA=new*ma; nB=new*mb; nC=max(0,new-nA-nB)
        cash += nA*small_first_cash('S2','A') + nB*small_first_cash('S2','B') + nC*small_first_cash('S2','C')
        cohorts += [{'n':nA,'seats':nA,'group':'S2','plan':'A','price':79.0,'mod':d%30,'age':0}, {'n':nB,'seats':nB,'group':'S2','plan':'B','price':159.0,'mod':d%30,'age':0}]
        if nC>0: cohorts.append({'n':nC,'seats':nC,'group':'S2','plan':'C','price':349.0,'mod':d%30,'age':0})
        def add_small(group, organic_rate, cv_start, cv_gain, bshare_mu, paid_leads=0.0):
            nonlocal cash, cohorts
            leads_g=max(0, random.gauss(active_s2*organic_rate*rel_sat + paid_leads, max(5,active_s2*organic_rate*0.35 + paid_leads*0.35)))
            cvg=max(0.0,min(0.75,random.gauss(cv_start + min(cv_gain, rel*cv_gain/21.0),0.08)))
            for bd,b in boosts:
                if d>=bd: cvg=min(0.80,cvg+min(0.05,b*0.09))
            newg=leads_g*cvg
            if newg<=0: return leads_g
            bshare=max(0.0,min(0.95,random.gauss(bshare_mu,0.14)))
            nb=newg*bshare; na=newg-nb
            cash += na*small_first_cash(group,'A') + nb*small_first_cash(group,'B')
